def clean(text):
    text = re.sub(r"<[^>]+>", "", str(text))
    text = html_module.unescape(text)
    return text.strip()


def read_csv_rows(path: Path):
    rows = []
    if not path.exists():
        return rows
    try:
        with path.open(newline="", encoding="utf-8-sig") as f:
            reader = csv.DictReader(f)
            for row in reader:
                if not row:
                    continue
                if not any(str(v or "").strip() for v in row.values()):
                    continue
                rows.append(row)
    except Exception:
        return []
    return rows


